"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[8907],{9605(e){e.exports=JSON.parse('{"tag":{"label":"compute","permalink":"/tags/compute","allTagsPath":"/tags","count":16,"items":[{"id":"architecture/system-topology/containerize-your-workload-where-applicable","title":"Containerize your workloads","description":"Containerizing workloads enables better resource utilisation and bin packing, reducing unnecessary compute allocation and embodied carbon compared to running full virtual machines.","permalink":"/architecture/system-topology/containerize-your-workload-where-applicable"},{"id":"architecture/system-topology/implement-stateless-design","title":"Implement stateless design","description":"Service state refers to the in-memory or on-disk data required by a service to function. State includes the data structures and member variables that the service reads and writes. Depending on how the service is architected, the state might also include files or other resources stored on the disk. Applications that consume large memory or on-disk data require larger VM sizes, especially for cloud computing where you would need larger VM SKUs to support high RAM capacity and multiple data disks.","permalink":"/architecture/system-topology/implement-stateless-design"},{"id":"operations/capacity-management/match-utilization-requirements-of-vm","title":"Match utilization requirements of virtual machines (VMs)","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/operations/capacity-management/match-utilization-requirements-of-vm"},{"id":"operations/capacity-management/match-utilization-requirements-with-pre-configured-server","title":"Match utilization requirements with pre-configured servers","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/operations/capacity-management/match-utilization-requirements-with-pre-configured-server"},{"id":"development/web-performance/minimize-main-thread-work","title":"Minimize main thread work","description":"Long-running JavaScript on the browser\'s main thread underutilises multi-core CPUs; offloading heavy computations to Web Workers or server-side implementations reduces energy consumption and improves efficiency.","permalink":"/development/web-performance/minimize-main-thread-work"},{"id":"operations/capacity-management/optimize-avg-cpu-utilization","title":"Optimize average CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/operations/capacity-management/optimize-avg-cpu-utilization"},{"id":"operations/capacity-management/optimize-peak-cpu-utilization","title":"Optimize peak CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/operations/capacity-management/optimize-peak-cpu-utilization"},{"id":"architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Placing VMs in the same region or availability zone minimises the physical distance data must travel between instances, reducing the energy consumed by network traversal.","permalink":"/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"operations/capacity-management/scale-infrastructure-with-user-load","title":"Scale infrastructure with user load","description":"Demand for resources depends on user load at any given time. However, most applications run without taking this into consideration. As a result,resources are underused and inefficient.","permalink":"/operations/capacity-management/scale-infrastructure-with-user-load"},{"id":"architecture/system-topology/scale-logical-components-independently","title":"Scale logical components independently","description":"Decomposing applications into independently scalable microservices allows each component to be right-sized for its own demand, reducing overall compute resource consumption and embodied carbon.","permalink":"/architecture/system-topology/scale-logical-components-independently"},{"id":"operations/scan-for-vulnerabilities","title":"Scan for vulnerabilities","description":"Many attacks on cloud infrastructure seek to misuse deployed resources, which leads to an unnecessary spike in usage and cost.","permalink":"/operations/scan-for-vulnerabilities"},{"id":"requirements/shed-lower-priority-traffic","title":"Shed lower priority traffic","description":"When resources are constrained during high-traffic events or when carbon intensity is high, more carbon emissions will be generated from your system. Adding more resources to support increased traffic requirements introduces more embodied carbon and more demand for electricity. Continuing to handle all requests during high carbon intensity will increase overall emissions for your system. Shedding traffic that is lower priority during these scenarios will save on resources and carbon emissions. This approach requires an understanding of your traffic, including which call requests are critical and which can best withstand retry attempts and failures.","permalink":"/requirements/shed-lower-priority-traffic"},{"id":"development/evaluate-whether-to-use-TLS-termination","title":"Terminate TLS at border gateway","description":"Transport Layer Security (TLS) ensures that all data passed between the web server and web browsers remain private and encrypted. However, terminating and re-establishing TLS increases CPU usage and might be unnecessary in certain architectures.","permalink":"/development/evaluate-whether-to-use-TLS-termination"},{"id":"operations/capacity-management/use-circuit-breaker","title":"Use circuit breaker patterns","description":"Modern applications need to communicate with other applications on a regular basis. Since these other applications have their own deployment schedule, downtimes and availability, the network connection to these application might have problems. If the other application is not reachable, all network requests against this other application will fail and future network requests are futile.","permalink":"/operations/capacity-management/use-circuit-breaker"},{"id":"operations/use-cloud-native-network-security-tools-and-controls","title":"Use cloud native network security tools and controls","description":"Network and web application firewalls provide protection against most common attacks and load shedding bad bots. These tools help to remove unnecessary data transmission and reduce the burden on the cloud infrastructure, while also using lower bandwidth and less infrastructure.","permalink":"/operations/use-cloud-native-network-security-tools-and-controls"},{"id":"architecture/technology-selection/use-energy-efficient-hardware","title":"Use cloud native processor VMs","description":"Cloud VMs built on energy-efficient processors, such as ARM-based cloud-native chips, can run scale-out workloads with significantly lower energy consumption and embodied carbon than traditional alternatives.","permalink":"/architecture/technology-selection/use-energy-efficient-hardware"}],"unlisted":false}}')}}]);